content:
:root {
  color-scheme: dark;
  --black: #050505;
  --black-2: #0b0909;
  --charcoal: #151111;
  --charcoal-2: #1d1715;
  --ivory: #f8f2ec;
  --ivory-2: #efe4db;
  --white: #ffffff;
  --muted: #b9aaa0;
  --muted-dark: #76645b;
  --rose: #d7a18c;
  --rose-2: #b87965;
  --rose-3: #f0c6b4;
  --line: rgba(215, 161, 140, 0.24);
  --line-dark: rgba(21, 17, 17, 0.1);
  --shadow: 0 24px 70px rgba(0, 0, 0, 0.34);
  --soft-shadow: 0 18px 50px rgba(55, 32, 24, 0.12);
  --radius: 8px;
  font-family:
    Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
}

* {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  min-width: 320px;
  background: var(--black);
  color: var(--ivory);
}

body,
button,
input,
select {
  font: inherit;
}

button {
  cursor: pointer;
}

a {
  color: inherit;
  text-decoration: none;
}

img {
  display: block;
  max-width: 100%;
}

input,
select {
  min-width: 0;
}

.site-shell {
  overflow: hidden;
  background: var(--black);
}

.navbar {
  position: fixed;
  inset: 0 0 auto;
  z-index: 20;
  display: grid;
  grid-template-columns: minmax(220px, 1fr) auto minmax(132px, 1fr);
  align-items: center;
  gap: 24px;
  min-height: 78px;
  padding: 14px 56px;
  border-bottom: 1px solid rgba(248, 242, 236, 0.08);
  background: rgba(5, 5, 5, 0.78);
  backdrop-filter: blur(22px);
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: 12px;
  width: fit-content;
}

.brand-mark {
  display: grid;
  width: 44px;
  height: 44px;
  place-items: center;
  border: 1px solid var(--rose);
  border-radius: 50%;
  background: linear-gradient(145deg, #1b1715, #050505);
  color: var(--rose);
  font-family: Georgia, "Times New Roman", serif;
  font-size: 1.4rem;
}

.brand-copy strong,
.brand-copy small {
  display: block;
}

.brand-copy strong {
  color: var(--ivory);
  font-family: Georgia, "Times New Roman", serif;
  font-size: 1.12rem;
  font-weight: 500;
}

.brand-copy small {
  margin-top: 3px;
  color: var(--muted);
  font-size: 0.76rem;
}

.nav-links {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 30px;
  color: var(--muted);
  font-size: 0.9rem;
}

.nav-links a {
  position: relative;
  padding: 8px 0;
}

.nav-links a::after {
  position: absolute;
  right: 0;
  bottom: 1px;
  left: 0;
  height: 1px;
  background: var(--rose);
  content: "";
  opacity: 0;
  transform: scaleX(0.45);
  transition: opacity 180ms ease, transform 180ms ease;
}

.nav-links a:hover,
.nav-links a:focus-visible {
  color: var(--ivory);
}

.nav-links a:hover::after,
.nav-links a:focus-visible::after {
  opacity: 1;
  transform: scaleX(1);
}

.nav-cta,
.primary-button,
.secondary-button,
.card-link,
.text-button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: 999px;
  font-weight: 850;
  transition:
    border-color 180ms ease,
    background 180ms ease,
    color 180ms ease,
    box-shadow 180ms ease,
    transform 180ms ease;
}

.nav-cta {
  justify-self: end;
  min-width: 126px;
  border: 1px solid var(--rose);
  color: var(--rose);
  padding: 11px 18px;
  font-size: 0.88rem;
}

.nav-cta:hover,
.nav-cta:focus-visible {
  background: var(--rose);
  color: var(--black);
  transform: translateY(-2px);
}

.hero {
  position: relative;
  min-height: 100vh;
  padding: 150px 72px 58px;
  overflow: hidden;
  isolation: isolate;
}

.hero-backdrop {
  position: absolute;
  inset: 0;
  z-index: -2;
  background:
    linear-gradient(90deg, rgba(5, 5, 5, 0.96), rgba(5, 5, 5, 0.72) 42%, rgba(5, 5, 5, 0.22)),
    linear-gradient(180deg, rgba(5, 5, 5, 0.1), rgba(5, 5, 5, 0.96)),
    url("https://images.unsplash.com/photo-1503736334956-4c8f8e92946d?auto=format&fit=crop&w=1900&q=84");
  background-position: center;
  background-size: cover;
  transform: scale(1.02);
}

.hero::after {
  position: absolute;
  right: 72px;
  bottom: 46px;
  width: 330px;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--rose), transparent);
  content: "";
  opacity: 0.82;
}

.hero-layout {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(320px, 430px);
  gap: 52px;
  align-items: end;
  min-height: calc(100vh - 208px);
}

.hero-copy {
  max-width: 760px;
  padding-bottom: 46px;
}

.eyebrow {
  margin: 0 0 14px;
  color: var(--rose);
  font-size: 0.76rem;
  font-weight: 850;
  letter-spacing: 0;
  text-transform: uppercase;
}

.hero h1,
.section-heading h2,
.detail-copy h2,
.booking-band h2 {
  margin: 0;
  font-family: Georgia, "Times New Roman", serif;
  font-weight: 500;
  line-height: 0.94;
}

.hero h1 {
  max-width: 760px;
  color: var(--ivory);
  font-size: 8.8rem;
}

.hero-lede {
  max-width: 650px;
  margin: 28px 0 0;
  color: rgba(248, 242, 236, 0.82);
  font-size: 1.16rem;
  line-height: 1.72;
}

.hero-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  margin-top: 34px;
}

.primary-button,
.secondary-button,
.card-link {
  min-height: 48px;
  padding: 0 22px;
}

.primary-button {
  border: 1px solid var(--rose);
  background: var(--rose);
  color: #120d0b;
  box-shadow: 0 16px 34px rgba(215, 161, 140, 0.18);
}

.primary-button:hover,
.primary-button:focus-visible {
  background: var(--rose-3);
  border-color: var(--rose-3);
  transform: translateY(-2px);
}

.secondary-button {
  border: 1px solid rgba(248, 242, 236, 0.34);
  color: var(--ivory);
}

.secondary-button:hover,
.secondary-button:focus-visible {
  border-color: var(--rose);
  color: var(--rose);
  transform: translateY(-2px);
}

.full-button {
  width: 100%;
}

.hero-reserve {
  display: grid;
  gap: 15px;
  border: 1px solid rgba(215, 161, 140, 0.26);
  border-radius: var(--radius);
  background: rgba(9, 8, 8, 0.74);
  padding: 24px;
  box-shadow: var(--shadow);
  backdrop-filter: blur(22px);
}

.hero-reserve label {
  display: grid;
  gap: 8px;
  color: var(--muted);
  font-size: 0.8rem;
  font-weight: 800;
}

.hero-reserve input,
.hero-reserve select {
  width: 100%;
  min-height: 46px;
  border: 1px solid rgba(248, 242, 236, 0.14);
  border-radius: var(--radius);
  background: rgba(255, 255, 255, 0.06);
  color: var(--ivory);
  padding: 0 12px;
}

.hero-reserve input:focus,
.hero-reserve select:focus {
  outline: 3px solid rgba(215, 161, 140, 0.16);
  border-color: var(--rose);
}

.form-pair {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
}

.form-note {
  margin: 0;
  color: var(--muted);
  font-size: 0.82rem;
  line-height: 1.55;
}

.trust-strip {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  border-top: 1px solid var(--line);
  border-bottom: 1px solid var(--line);
  background: #0a0808;
}

.trust-item {
  display: grid;
  gap: 4px;
  min-height: 104px;
  place-items: center;
  border-right: 1px solid var(--line);
  text-align: center;
}

.trust-item strong {
  color: var(--rose);
  font-family: Georgia, "Times New Roman", serif;
  font-size: 2.25rem;
  font-weight: 500;
}

.trust-item span {
  color: var(--muted);
  font-size: 0.9rem;
  font-weight: 750;
}

.section {
  padding: 102px 72px;
}

.section-light {
  background:
    linear-gradient(180deg, #f9f2eb, #f4e8df);
  color: #15100e;
}

.section-heading {
  display: grid;
  gap: 14px;
  max-width: 880px;
  margin-bottom: 36px;
}

.section-heading h2,
.detail-copy h2,
.booking-band h2 {
  font-size: 4.8rem;
}

.section-heading p:not(.eyebrow),
.detail-copy p,
.booking-band p {
  max-width: 720px;
  margin: 0;
  color: var(--muted-dark);
  font-size: 1rem;
  line-height: 1.72;
}

.fleet-grid {
  display: grid;
  grid-template-columns: repeat(5, minmax(0, 1fr));
  gap: 16px;
}

.fleet-card {
  display: grid;
  overflow: hidden;
  border: 1px solid rgba(184, 121, 101, 0.22);
  border-radius: var(--radius);
  background: rgba(255, 250, 245, 0.86);
  box-shadow: var(--soft-shadow);
  transition:
    border-color 200ms ease,
    box-shadow 200ms ease,
    transform 200ms ease;
}

.fleet-card:hover,
.fleet-card:focus-within {
  border-color: rgba(184, 121, 101, 0.58);
  box-shadow: 0 30px 70px rgba(55, 32, 24, 0.18);
  transform: translateY(-5px);
}

.fleet-media {
  position: relative;
  min-height: 230px;
  overflow: hidden;
  background: #171313;
}

.fleet-year {
  position: absolute;
  right: 12px;
  bottom: 12px;
  z-index: 1;
  border: 1px solid rgba(248, 242, 236, 0.26);
  border-radius: 999px;
  background: rgba(5, 5, 5, 0.62);
  color: var(--ivory);
  padding: 6px 9px;
  font-size: 0.78rem;
  font-weight: 850;
}

.vehicle-art {
  --vehicle-paint: #f7f0e8;
  --vehicle-paint-deep: #d7c8bc;
  --vehicle-accent: var(--rose);
  position: relative;
  width: 100%;
  height: 100%;
  min-height: 230px;
  overflow: hidden;
  background:
    radial-gradient(circle at 28% 22%, rgba(248, 242, 236, 0.18), transparent 28%),
    linear-gradient(145deg, rgba(248, 242, 236, 0.08), rgba(248, 242, 236, 0.015)),
    #151111;
  isolation: isolate;
}

.vehicle-art::before {
  position: absolute;
  inset: 18px;
  border: 1px solid rgba(248, 242, 236, 0.08);
  border-radius: var(--radius);
  content: "";
}

.vehicle-art::after {
  position: absolute;
  right: 12%;
  bottom: 24%;
  left: 12%;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(248, 242, 236, 0.4), transparent);
  content: "";
}

.vehicle-art-glow {
  position: absolute;
  inset: 22% 12% auto;
  height: 44%;
  border-radius: 50%;
  background: radial-gradient(circle, color-mix(in srgb, var(--vehicle-accent) 52%, transparent), transparent 66%);
  filter: blur(24px);
  opacity: 0.78;
}

.vehicle-art-body,
.vehicle-art-roof {
  position: absolute;
  left: 50%;
  z-index: 2;
  transform: translateX(-50%);
}

.vehicle-art-body {
  bottom: 30%;
  width: 72%;
  height: 22%;
  border: 1px solid rgba(248, 242, 236, 0.24);
  border-radius: 999px 999px 30px 30px;
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.42), transparent 38%),
    linear-gradient(90deg, var(--vehicle-paint-deep), var(--vehicle-paint), var(--vehicle-paint-deep));
  box-shadow: 0 22px 42px rgba(0, 0, 0, 0.4);
}

.vehicle-art-roof {
  bottom: 46%;
  width: 42%;
  height: 20%;
  border: 1px solid rgba(248, 242, 236, 0.2);
  border-radius: 80px 80px 16px 16px;
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.34), transparent 48%),
    linear-gradient(90deg, color-mix(in srgb, var(--vehicle-paint-deep) 70%, #050505), var(--vehicle-paint));
  clip-path: polygon(12% 100%, 28% 8%, 72% 8%, 92% 100%);
}

.vehicle-art-wheel {
  position: absolute;
  bottom: 24%;
  z-index: 3;
  width: 13%;
  aspect-ratio: 1;
  border: 7px solid #080707;
  border-radius: 50%;
  background:
    radial-gradient(circle, rgba(248, 242, 236, 0.52) 0 18%, transparent 19%),
    radial-gradient(circle, #272120 0 52%, #090808 53%);
  box-shadow: inset 0 0 0 2px rgba(215, 161, 140, 0.26);
}

.vehicle-art-wheel-front {
  right: 22%;
}

.vehicle-art-wheel-rear {
  left: 22%;
}

.vehicle-art-meta {
  position: absolute;
  right: 18px;
  bottom: 18px;
  left: 18px;
  z-index: 4;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.vehicle-art-meta span,
.vehicle-art-meta strong {
  border: 1px solid rgba(248, 242, 236, 0.14);
  border-radius: 999px;
  background: rgba(5, 5, 5, 0.58);
  color: var(--ivory);
  padding: 6px 9px;
  font-size: 0.75rem;
  font-weight: 850;
}

.vehicle-art-meta span {
  color: var(--rose);
}

.vehicle-art-large {
  min-height: 560px;
}

.vehicle-art-large .vehicle-art-body {
  bottom: 32%;
  height: 20%;
}

.vehicle-art-large .vehicle-art-roof {
  bottom: 48%;
}

.vehicle-art-tesla-model-3-performance {
  --vehicle-paint: #fbf7f1;
  --vehicle-paint-deep: #d8d3ce;
  --vehicle-accent: #f8f2ec;
}

.vehicle-art-lamborghini-urus {
  --vehicle-paint: #ff8a30;
  --vehicle-paint-deep: #a94416;
  --vehicle-accent: #ff9b42;
}

.vehicle-art-range-rover-sport-svr {
  --vehicle-paint: #2a2928;
  --vehicle-paint-deep: #0e0d0c;
  --vehicle-accent: #b9aaa0;
}

.vehicle-art-bmw-m440i-convertible {
  --vehicle-paint: #79c8f5;
  --vehicle-paint-deep: #276f99;
  --vehicle-accent: #79c8f5;
}

.vehicle-art-bmw-m140i-shadow-edition {
  --vehicle-paint: #3a3735;
  --vehicle-paint-deep: #11100f;
  --vehicle-accent: #8d827b;
}

.fleet-card-body {
  display: grid;
  gap: 15px;
  padding: 18px;
}

.fleet-title-row {
  display: grid;
  gap: 11px;
}

.fleet-title-row p {
  margin: 0 0 7px;
  color: var(--rose-2);
  font-size: 0.78rem;
  font-weight: 850;
  text-transform: uppercase;
}

.fleet-title-row h3 {
  margin: 0;
  color: #15100e;
  font-family: Georgia, "Times New Roman", serif;
  font-size: 1.45rem;
  font-weight: 500;
  line-height: 1.05;
}

.fleet-title-row strong {
  color: var(--rose-2);
  font-size: 1rem;
}

.fleet-finish {
  margin: 0;
  color: var(--muted-dark);
  font-size: 0.9rem;
  line-height: 1.45;
}

.spec-list,
.detail-specs {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin: 0;
  padding: 0;
  list-style: none;
}

.spec-list li,
.detail-specs li {
  border: 1px solid rgba(184, 121, 101, 0.22);
  border-radius: 999px;
  color: #4c3a32;
  padding: 7px 10px;
  font-size: 0.78rem;
  font-weight: 800;
}

.card-actions {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  margin-top: 2px;
}

.text-button {
  border: 0;
  background: transparent;
  color: #15100e;
  padding: 0;
  font-size: 0.86rem;
}

.text-button:hover,
.text-button:focus-visible {
  color: var(--rose-2);
}

.card-link {
  min-height: 38px;
  border: 1px solid #15100e;
  color: #15100e;
  padding: 0 15px;
  font-size: 0.84rem;
}

.card-link:hover,
.card-link:focus-visible {
  border-color: var(--rose-2);
  background: var(--rose-2);
  color: #fffaf5;
}

.detail-section {
  display: grid;
  grid-template-columns: minmax(0, 1.12fr) minmax(360px, 0.88fr);
  min-height: 760px;
  background: var(--black);
}

.detail-media {
  position: relative;
  min-height: 560px;
  overflow: hidden;
}

.detail-media::after {
  position: absolute;
  inset: 0;
  background:
    linear-gradient(90deg, rgba(5, 5, 5, 0.08), rgba(5, 5, 5, 0.42)),
    linear-gradient(180deg, transparent, rgba(5, 5, 5, 0.76));
  content: "";
}

.detail-copy {
  display: grid;
  align-content: center;
  gap: 24px;
  padding: 72px;
  border-left: 1px solid var(--line);
  background:
    radial-gradient(circle at top right, rgba(215, 161, 140, 0.16), transparent 34%),
    #090808;
}

.detail-copy p {
  color: rgba(248, 242, 236, 0.75);
}

.detail-meta {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  border: 1px solid var(--line);
  border-radius: var(--radius);
  overflow: hidden;
}

.detail-meta div {
  display: grid;
  gap: 4px;
  padding: 15px;
}

.detail-meta div + div {
  border-left: 1px solid var(--line);
}

.detail-meta span {
  color: var(--muted);
  font-size: 0.74rem;
  font-weight: 800;
  text-transform: uppercase;
}

.detail-meta strong {
  color: var(--ivory);
  font-family: Georgia, "Times New Roman", serif;
  font-size: 1.2rem;
  font-weight: 500;
}

.detail-specs li {
  border-color: rgba(248, 242, 236, 0.16);
  color: var(--ivory-2);
}

.best-for {
  border-left: 1px solid var(--rose);
  padding-left: 16px;
}

.service-section {
  background:
    linear-gradient(180deg, rgba(13, 10, 10, 0.96), rgba(5, 5, 5, 1)),
    url("https://images.unsplash.com/photo-1549924231-f129b911e442?auto=format&fit=crop&w=1800&q=84");
  background-position: center;
  background-size: cover;
}

.service-section .section-heading p:not(.eyebrow) {
  color: var(--muted);
}

.service-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 16px;
}

.service-card {
  min-height: 260px;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  background: rgba(12, 10, 10, 0.78);
  padding: 24px;
  box-shadow: var(--shadow);
  backdrop-filter: blur(16px);
}

.service-card span {
  color: var(--rose);
  font-family: Georgia, "Times New Roman", serif;
  font-size: 2rem;
}

.service-card h3 {
  margin: 44px 0 12px;
  font-family: Georgia, "Times New Roman", serif;
  font-size: 1.5rem;
  font-weight: 500;
}

.service-card p {
  margin: 0;
  color: var(--muted);
  line-height: 1.62;
}

.booking-band {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(320px, 430px);
  gap: 42px;
  align-items: center;
  padding: 96px 72px;
  border-top: 1px solid var(--line);
  border-bottom: 1px solid var(--line);
  background: #090808;
}

.booking-band p {
  color: var(--muted);
}

.booking-preview {
  display: grid;
  gap: 18px;
}

.map-preview {
  position: relative;
  display: grid;
  align-content: end;
  gap: 8px;
  min-height: 260px;
  overflow: hidden;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  background:
    linear-gradient(135deg, rgba(215, 161, 140, 0.16) 0 2px, transparent 2px 42px),
    linear-gradient(45deg, rgba(248, 242, 236, 0.08) 0 1px, transparent 1px 38px),
    #14100f;
  padding: 22px;
}

.map-preview::before {
  position: absolute;
  top: 44%;
  left: 50%;
  width: 18px;
  height: 18px;
  border: 4px solid var(--rose);
  border-radius: 50%;
  box-shadow: 0 0 0 16px rgba(215, 161, 140, 0.12);
  content: "";
  transform: translate(-50%, -50%);
}

.map-preview span {
  color: var(--rose);
  font-size: 0.8rem;
  font-weight: 850;
  text-transform: uppercase;
}

.map-preview strong {
  max-width: 300px;
  color: var(--ivory);
  font-family: Georgia, "Times New Roman", serif;
  font-size: 1.65rem;
  font-weight: 500;
}

.reviews-section {
  background:
    linear-gradient(180deg, #f9f2eb, #efe2d8);
}

.reviews-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 16px;
}

.review-card {
  display: grid;
  gap: 28px;
  min-height: 300px;
  border: 1px solid rgba(184, 121, 101, 0.22);
  border-radius: var(--radius);
  background: rgba(255, 252, 248, 0.78);
  padding: 26px;
  box-shadow: var(--soft-shadow);
}

.review-card p {
  margin: 0;
  color: #251b17;
  font-family: Georgia, "Times New Roman", serif;
  font-size: 1.36rem;
  line-height: 1.46;
}

.review-card div {
  align-self: end;
}

.review-card strong,
.review-card span {
  display: block;
}

.review-card strong {
  color: var(--rose-2);
}

.review-card span {
  margin-top: 5px;
  color: var(--muted-dark);
  font-size: 0.86rem;
}

.footer {
  display: grid;
  grid-template-columns: minmax(280px, 1fr) auto auto;
  gap: 44px;
  padding: 42px 72px;
  border-top: 1px solid var(--line);
  background: var(--black);
}

.footer p {
  max-width: 560px;
  margin: 18px 0 0;
  color: var(--muted);
  line-height: 1.65;
}

.footer-column {
  display: grid;
  align-content: start;
  gap: 10px;
  min-width: 140px;
}

.footer-column strong {
  color: var(--ivory);
  font-family: Georgia, "Times New Roman", serif;
  font-weight: 500;
}

.footer-column a {
  color: var(--muted);
}

.footer-column a:hover,
.footer-column a:focus-visible {
  color: var(--rose);
}

@media (max-width: 1320px) {
  .fleet-grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }
}

@media (max-width: 1060px) {
  .navbar {
    grid-template-columns: 1fr auto;
    padding: 14px 26px;
  }

  .nav-links {
    order: 3;
    grid-column: 1 / -1;
    justify-content: flex-start;
    gap: 22px;
    overflow-x: auto;
    padding-bottom: 3px;
  }

  .hero {
    padding: 154px 28px 42px;
  }

  .hero-layout,
  .detail-section,
  .booking-band {
    grid-template-columns: 1fr;
  }

  .hero-copy {
    padding-bottom: 0;
  }

  .hero h1 {
    font-size: 6.4rem;
  }

  .detail-copy {
    border-left: 0;
    border-top: 1px solid var(--line);
    padding: 56px 28px;
  }

  .section,
  .booking-band {
    padding: 76px 28px;
  }

  .section-heading h2,
  .detail-copy h2,
  .booking-band h2 {
    font-size: 3.75rem;
  }

  .trust-strip,
  .service-grid,
  .reviews-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .footer {
    grid-template-columns: 1fr 1fr;
    padding: 38px 28px;
  }
}

@media (max-width: 720px) {
  .navbar {
    min-height: 68px;
    padding: 12px 16px;
  }

  .brand-copy small,
  .nav-cta {
    display: none;
  }

  .nav-links {
    gap: 18px;
    font-size: 0.84rem;
  }

  .hero {
    min-height: auto;
    padding: 136px 16px 34px;
  }

  .hero::after {
    right: 16px;
    width: 180px;
  }

  .hero-layout {
    gap: 28px;
    min-height: auto;
  }

  .hero h1 {
    font-size: 4.45rem;
  }

  .hero-lede {
    font-size: 1rem;
  }

  .hero-actions,
  .card-actions {
    align-items: stretch;
    flex-direction: column;
  }

  .primary-button,
  .secondary-button,
  .card-link {
    width: 100%;
  }

  .form-pair,
  .trust-strip,
  .fleet-grid,
  .service-grid,
  .reviews-grid,
  .detail-meta,
  .footer {
    grid-template-columns: 1fr;
  }

  .trust-item,
  .detail-meta div + div {
    border-left: 0;
  }

  .trust-item + .trust-item,
  .detail-meta div + div {
    border-top: 1px solid var(--line);
  }

  .section,
  .booking-band {
    padding: 58px 16px;
  }

  .section-heading h2,
  .detail-copy h2,
  .booking-band h2 {
    font-size: 2.7rem;
  }

  .fleet-media {
    min-height: 245px;
  }

  .detail-media {
    min-height: 390px;
  }

  .detail-copy {
    padding: 42px 16px;
  }

  .service-card {
    min-height: 220px;
  }

  .footer {
    gap: 28px;
    padding: 34px 16px;
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    scroll-behavior: auto !important;
    transition-duration: 0.01ms !important;
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
  }
}

:root {
  color-scheme: dark;
  --black: #050505;
  --black-2: #0b0909;
  --charcoal: #151111;
  --charcoal-2: #1d1715;
  --ivory: #f8f2ec;
  --ivory-2: #efe4db;
  --white: #ffffff;
  --muted: #b9aaa0;
  --muted-dark: #76645b;
  --rose: #d7a18c;
  --rose-2: #b87965;
  --rose-3: #f0c6b4;
  --line: rgba(215, 161, 140, 0.24);
  --line-soft: rgba(248, 242, 236, 0.12);
  --shadow: 0 24px 70px rgba(0, 0, 0, 0.34);
  --radius: 8px;
  font-family:
    Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
}

* {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  position: relative;
  min-width: 320px;
  min-height: 100vh;
  margin: 0;
  overflow-x: hidden;
  background: var(--black);
  color: var(--ivory);
  isolation: isolate;
}

body::before {
  position: fixed;
  inset: 0;
  z-index: -2;
  background:
    linear-gradient(90deg, rgba(5, 5, 5, 0.96), rgba(5, 5, 5, 0.72) 42%, rgba(5, 5, 5, 0.22)),
    linear-gradient(180deg, rgba(5, 5, 5, 0.1), rgba(5, 5, 5, 0.96)),
    url("https://images.unsplash.com/photo-1503736334956-4c8f8e92946d?auto=format&fit=crop&w=1900&q=84");
  background-position: center;
  background-size: cover;
  content: "";
  transform: scale(1.02);
}

body::after {
  position: fixed;
  inset: 0;
  z-index: -1;
  background:
    radial-gradient(circle at 18% 16%, rgba(215, 161, 140, 0.14), transparent 28rem),
    linear-gradient(180deg, transparent 62%, #050505);
  content: "";
  pointer-events: none;
}

body,
button,
input,
select {
  font: inherit;
}

button {
  cursor: pointer;
}

a {
  color: inherit;
  text-decoration: none;
}

img {
  display: block;
  max-width: 100%;
}

input,
select {
  min-width: 0;
}

.flow-shell {
  position: relative;
  min-height: 100vh;
  padding: 150px 72px 58px;
  overflow: hidden;
  isolation: isolate;
}

.flow-shell::after {
  position: fixed;
  right: 72px;
  bottom: 46px;
  width: 330px;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--rose), transparent);
  content: "";
  opacity: 0.82;
  pointer-events: none;
}

.flow-nav {
  position: fixed;
  inset: 0 0 auto;
  z-index: 20;
  display: grid;
  grid-template-columns: minmax(220px, 1fr) auto minmax(132px, 1fr);
  align-items: center;
  gap: 24px;
  min-height: 78px;
  margin: 0;
  padding: 14px 56px;
  border-bottom: 1px solid rgba(248, 242, 236, 0.08);
  background: rgba(5, 5, 5, 0.78);
  backdrop-filter: blur(22px);
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: 12px;
  width: fit-content;
}

.brand-mark {
  display: grid;
  width: 44px;
  height: 44px;
  place-items: center;
  border: 1px solid var(--rose);
  border-radius: 50%;
  background: linear-gradient(145deg, #1b1715, #050505);
  color: var(--rose);
  font-family: Georgia, "Times New Roman", serif;
  font-size: 1.4rem;
}

.brand-copy strong,
.brand-copy small {
  display: block;
}

.brand-copy strong {
  color: var(--ivory);
  font-family: Georgia, "Times New Roman", serif;
  font-size: 1.12rem;
  font-weight: 500;
}

.brand-copy small {
  margin-top: 3px;
  color: var(--muted);
  font-size: 0.76rem;
}

.flow-nav-links {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 30px;
  color: var(--muted);
  font-size: 0.9rem;
}

.flow-nav-links a {
  position: relative;
  padding: 8px 0;
  transition: color 180ms ease, border-color 180ms ease, background 180ms ease, transform 180ms ease;
}

.flow-nav-links a::after {
  position: absolute;
  right: 0;
  bottom: 1px;
  left: 0;
  height: 1px;
  background: var(--rose);
  content: "";
  opacity: 0;
  transform: scaleX(0.45);
  transition: opacity 180ms ease, transform 180ms ease;
}

.flow-nav-links a:hover,
.flow-nav-links a:focus-visible {
  color: var(--ivory);
}

.flow-nav-links a:hover::after,
.flow-nav-links a:focus-visible::after {
  opacity: 1;
  transform: scaleX(1);
}

.flow-back {
  justify-self: end;
  border: 1px solid var(--line);
  border-radius: 999px;
  color: var(--rose);
  padding: 10px 16px;
  font-size: 0.86rem;
  font-weight: 850;
}

.flow-back:hover,
.flow-back:focus-visible {
  border-color: var(--rose-3);
  background: rgba(215, 161, 140, 0.1);
  color: var(--rose-3);
  transform: translateY(-2px);
}

.flow-trust-strip {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  width: min(1380px, 100%);
  margin: -18px auto 38px;
  border-top: 1px solid var(--line);
  border-bottom: 1px solid var(--line);
  background: rgba(10, 8, 8, 0.82);
  box-shadow: 0 20px 52px rgba(0, 0, 0, 0.18);
  backdrop-filter: blur(18px);
}

.flow-trust-strip div {
  display: grid;
  gap: 4px;
  min-height: 96px;
  place-items: center;
  border-right: 1px solid var(--line);
  text-align: center;
}

.flow-trust-strip div:last-child {
  border-right: 0;
}

.flow-trust-strip strong {
  color: var(--rose);
  font-family: Georgia, "Times New Roman", serif;
  font-size: 2.1rem;
  font-weight: 500;
}

.flow-trust-strip span {
  color: var(--muted);
  font-size: 0.86rem;
  font-weight: 750;
}

.flow-stage {
  display: grid;
  grid-template-columns: minmax(290px, 0.76fr) minmax(0, 1.24fr);
  gap: 48px;
  align-items: end;
  min-height: calc(100vh - 208px);
  width: min(1380px, 100%);
  margin: 0 auto;
}

.compact-stage {
  grid-template-columns: minmax(300px, 0.9fr) minmax(420px, 0.82fr);
  justify-content: space-between;
}

.flow-intro {
  position: sticky;
  top: 28px;
  display: grid;
  gap: 22px;
  max-width: 680px;
  padding-bottom: 46px;
}

.eyebrow {
  margin: 0;
  color: var(--rose);
  font-size: 0.76rem;
  font-weight: 850;
  letter-spacing: 0;
  text-transform: uppercase;
}

h1,
h2,
h3,
p {
  margin-top: 0;
}

h1,
h2 {
  margin-bottom: 0;
  font-family: Georgia, "Times New Roman", serif;
  font-weight: 500;
  line-height: 0.94;
}

h1 {
  max-width: 760px;
  color: var(--ivory);
  font-size: clamp(4.45rem, 7.2vw, 7.4rem);
}

h2 {
  color: var(--ivory);
  font-size: clamp(2rem, 3.4vw, 3.9rem);
}

.flow-intro p:not(.eyebrow),
.summary-copy,
.notice-card p,
.secure-note,
.client-proof span {
  color: rgba(248, 242, 236, 0.74);
  line-height: 1.68;
}

.step-row {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 8px;
  margin-top: 6px;
}

.step {
  min-height: 44px;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  padding: 12px 10px;
  color: var(--muted);
  font-size: 0.78rem;
  font-weight: 850;
  text-align: center;
}

.step.active {
  border-color: var(--rose);
  background: rgba(215, 161, 140, 0.13);
  color: var(--ivory);
  box-shadow: 0 14px 34px rgba(215, 161, 140, 0.08);
}

.intro-stat-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 12px;
}

.intro-stat-grid div {
  border: 1px solid rgba(248, 242, 236, 0.1);
  border-radius: var(--radius);
  background: rgba(248, 242, 236, 0.045);
  padding: 18px;
}

.intro-stat-grid strong {
  display: block;
  color: var(--rose);
  font-family: Georgia, "Times New Roman", serif;
  font-size: 2rem;
  font-weight: 500;
}

.intro-stat-grid span {
  color: var(--muted);
  font-size: 0.86rem;
}

.flow-workspace {
  display: grid;
  gap: 18px;
  align-items: start;
}

.booking-workspace {
  grid-template-columns: minmax(0, 1.15fr) minmax(300px, 0.85fr);
}

.payment-workspace {
  grid-template-columns: minmax(300px, 0.86fr) minmax(330px, 0.74fr);
}

.account-workspace {
  grid-template-columns: minmax(330px, 0.88fr) minmax(280px, 0.72fr);
  align-items: stretch;
}

.flow-panel {
  border: 1px solid rgba(215, 161, 140, 0.26);
  border-radius: var(--radius);
  background:
    linear-gradient(140deg, rgba(248, 242, 236, 0.055), rgba(248, 242, 236, 0.018)),
    rgba(9, 8, 8, 0.74);
  box-shadow: var(--shadow);
  backdrop-filter: blur(22px);
}

.booking-panel,
.payment-card,
.account-card,
.client-proof,
.order-review,
.vehicle-summary {
  padding: 28px;
}

.form-grid {
  display: grid;
  gap: 16px;
}

.two-column {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.panel-heading {
  display: grid;
  gap: 10px;
}

.panel-heading h2 {
  font-size: clamp(2rem, 4vw, 3.2rem);
}

.compact-heading h2 {
  font-size: clamp(1.8rem, 3vw, 2.6rem);
}

.compact-heading span {
  color: var(--rose);
  font-weight: 850;
}

.field {
  display: grid;
  gap: 8px;
  color: var(--muted);
  font-size: 0.82rem;
  font-weight: 850;
}

.field input,
.field select {
  width: 100%;
  min-height: 52px;
  border: 1px solid rgba(248, 242, 236, 0.14);
  border-radius: var(--radius);
  background: rgba(255, 255, 255, 0.06);
  color: var(--ivory);
  padding: 0 14px;
  outline: none;
  transition: border-color 180ms ease, background 180ms ease, box-shadow 180ms ease;
}

.field input::placeholder {
  color: rgba(248, 242, 236, 0.42);
}

.field input:focus,
.field select:focus {
  border-color: var(--rose);
  background: rgba(255, 255, 255, 0.08);
  box-shadow: 0 0 0 4px rgba(215, 161, 140, 0.14);
}

.field select option {
  color: #16100e;
}

.date-field {
  position: relative;
}

.date-trigger {
  display: grid;
  gap: 4px;
  width: 100%;
  min-height: 52px;
  border: 1px solid rgba(248, 242, 236, 0.14);
  border-radius: var(--radius);
  background:
    linear-gradient(135deg, rgba(215, 161, 140, 0.09), rgba(255, 255, 255, 0.035)),
    rgba(255, 255, 255, 0.045);
  color: var(--ivory);
  padding: 9px 14px;
  text-align: left;
  transition: border-color 180ms ease, background 180ms ease, box-shadow 180ms ease, transform 180ms ease;
}

.date-trigger::after {
  position: absolute;
  right: 14px;
  bottom: 15px;
  width: 9px;
  height: 9px;
  border-right: 1px solid var(--rose);
  border-bottom: 1px solid var(--rose);
  content: "";
  transform: rotate(45deg);
}

.date-trigger:hover,
.date-trigger:focus-visible,
.date-trigger[aria-expanded="true"] {
  border-color: var(--rose);
  background:
    linear-gradient(135deg, rgba(215, 161, 140, 0.14), rgba(255, 255, 255, 0.055)),
    rgba(255, 255, 255, 0.065);
  box-shadow: 0 0 0 4px rgba(215, 161, 140, 0.12);
  outline: none;
}

.date-trigger span {
  color: rgba(248, 242, 236, 0.66);
  font-weight: 850;
}

.date-trigger.has-value span {
  color: var(--ivory);
}

.date-trigger small {
  color: var(--rose);
  font-size: 0.74rem;
  font-weight: 850;
  text-transform: uppercase;
}

.date-popover {
  position: absolute;
  top: calc(100% + 10px);
  left: 0;
  z-index: 35;
  width: min(360px, calc(100vw - 32px));
  border: 1px solid rgba(215, 161, 140, 0.32);
  border-radius: var(--radius);
  background:
    radial-gradient(circle at 84% 0%, rgba(215, 161, 140, 0.14), transparent 34%),
    #0b0909;
  box-shadow: 0 28px 80px rgba(0, 0, 0, 0.46);
  padding: 14px;
}

.date-popover[hidden] {
  display: none;
}

.calendar-topline,
.calendar-header,
.calendar-weekdays,
.calendar-grid {
  display: grid;
}

.calendar-topline {
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 12px;
  align-items: center;
  margin-bottom: 12px;
}

.calendar-topline span {
  color: var(--rose);
  font-size: 0.74rem;
  font-weight: 850;
  text-transform: uppercase;
}

.calendar-close,
.calendar-nav {
  border: 1px solid rgba(248, 242, 236, 0.12);
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.045);
  color: var(--ivory);
  font-weight: 850;
}

.calendar-close {
  min-height: 32px;
  padding: 0 11px;
  color: var(--muted);
  font-size: 0.76rem;
}

.calendar-header {
  grid-template-columns: 38px minmax(0, 1fr) 38px;
  gap: 10px;
  align-items: center;
  margin-bottom: 12px;
}

.calendar-header strong {
  color: var(--ivory);
  font-family: Georgia, "Times New Roman", serif;
  font-size: 1.35rem;
  font-weight: 500;
  text-align: center;
}

.calendar-nav {
  width: 38px;
  height: 38px;
  color: var(--rose);
  font-size: 1.2rem;
  transition: border-color 180ms ease, background 180ms ease, transform 180ms ease;
}

.calendar-nav:hover,
.calendar-nav:focus-visible,
.calendar-close:hover,
.calendar-close:focus-visible {
  border-color: var(--rose);
  background: rgba(215, 161, 140, 0.12);
  outline: none;
  transform: translateY(-1px);
}

.calendar-weekdays,
.calendar-grid {
  grid-template-columns: repeat(7, minmax(0, 1fr));
  gap: 6px;
}

.calendar-weekdays {
  margin-bottom: 6px;
}

.calendar-weekdays span {
  color: rgba(248, 242, 236, 0.42);
  font-size: 0.68rem;
  font-weight: 850;
  text-align: center;
  text-transform: uppercase;
}

.calendar-day {
  display: grid;
  min-height: 38px;
  place-items: center;
  border: 1px solid transparent;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.045);
  color: rgba(248, 242, 236, 0.84);
  font-size: 0.86rem;
  font-weight: 850;
  transition: border-color 180ms ease, background 180ms ease, color 180ms ease, transform 180ms ease;
}

.calendar-day:hover,
.calendar-day:focus-visible {
  border-color: rgba(215, 161, 140, 0.72);
  color: var(--ivory);
  outline: none;
  transform: translateY(-1px);
}

.calendar-day.is-muted {
  color: rgba(248, 242, 236, 0.34);
}

.calendar-day.is-today {
  border-color: rgba(248, 242, 236, 0.2);
}

.calendar-day.is-selected {
  border-color: var(--rose);
  background: var(--rose);
  color: #120d0b;
  box-shadow: 0 10px 24px rgba(215, 161, 140, 0.16);
}

.calendar-day:disabled {
  cursor: not-allowed;
  color: rgba(248, 242, 236, 0.18);
  opacity: 0.55;
  transform: none;
}

.choice-grid {
  display: grid;
  grid-template-columns: repeat(5, minmax(0, 1fr));
  gap: 10px;
}

.choice-card {
  position: relative;
  display: grid;
  min-height: 218px;
  overflow: hidden;
  border: 1px solid rgba(248, 242, 236, 0.12);
  border-radius: var(--radius);
  background: rgba(17, 15, 14, 0.88);
  cursor: pointer;
  transition: border-color 180ms ease, box-shadow 180ms ease, transform 180ms ease;
}

.choice-card::after {
  position: absolute;
  inset: 0;
  border: 1px solid transparent;
  border-radius: inherit;
  content: "";
  pointer-events: none;
  transition: border-color 180ms ease;
}

.choice-card:hover,
.choice-card:focus-within,
.choice-card.is-selected {
  border-color: rgba(215, 161, 140, 0.78);
  box-shadow: 0 18px 42px rgba(0, 0, 0, 0.28);
  transform: translateY(-3px);
}

.choice-card.is-selected::after {
  border-color: rgba(240, 198, 180, 0.42);
}

.choice-card input {
  position: absolute;
  top: 12px;
  left: 12px;
  z-index: 2;
  width: 18px;
  height: 18px;
  accent-color: var(--rose);
}

.choice-card .choice-name,
.choice-card small,
.choice-card strong {
  display: block;
  padding-inline: 12px;
}

.choice-card .choice-name {
  margin-top: 12px;
  color: var(--ivory);
  font-family: Georgia, "Times New Roman", serif;
  font-size: 1rem;
  line-height: 1.08;
}

.choice-card small {
  margin-top: 7px;
  color: rgba(248, 242, 236, 0.56);
  font-size: 0.74rem;
  line-height: 1.25;
